def validate(args, output):
    s = args[0]
    if not isinstance(output, str) or len(output) != len(s):
        return False
    from collections import Counter
    if Counter(output) != Counter(s):
        return False
    # Each run of identical characters must be contiguous
    # and runs must be in non-increasing frequency order
    i = 0
    runs = []
    while i < len(output):
        c = output[i]
        j = i
        while j < len(output) and output[j] == c:
            j += 1
        runs.append((j - i, c))
        i = j
    # No character may appear in more than one run
    seen_chars = set()
    for freq, c in runs:
        if c in seen_chars:
            return False
        seen_chars.add(c)
    # Frequencies must be non-increasing
    for k in range(len(runs) - 1):
        if runs[k][0] < runs[k+1][0]:
            return False
    return True

