function validate(args, output) {
    const s = args[0];
    if (typeof output !== 'string' || output.length !== s.length) return false;
    // Check same characters
    const freqS = new Map();
    for (const c of s) freqS.set(c, (freqS.get(c) || 0) + 1);
    const freqOut = new Map();
    for (const c of output) freqOut.set(c, (freqOut.get(c) || 0) + 1);
    if (freqS.size !== freqOut.size) return false;
    for (const [c, cnt] of freqS) {
        if (freqOut.get(c) !== cnt) return false;
    }
    // Parse runs
    const runs = [];
    let i = 0;
    while (i < output.length) {
        const c = output[i];
        let j = i;
        while (j < output.length && output[j] === c) j++;
        runs.push([j - i, c]);
        i = j;
    }
    // No character repeated across multiple runs
    const seenChars = new Set();
    for (const [freq, c] of runs) {
        if (seenChars.has(c)) return false;
        seenChars.add(c);
    }
    // Frequencies non-increasing
    for (let k = 0; k < runs.length - 1; k++) {
        if (runs[k][0] < runs[k+1][0]) return false;
    }
    return true;
}

