class Solution:
    def frequencySort(self, s):
        from collections import Counter
        freq = Counter(s)
        # Sort by frequency desc then character for determinism
        chars = sorted(freq.keys(), key=lambda c: (-freq[c], c))
        return ''.join(c * freq[c] for c in chars)

